"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[587],{82873:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Creates a new builder pre-populated with all default values.","params":[],"returns":[{"desc":"","lua_type":"BehaviorBuilder"}],"function_type":"static","source":{"line":55,"path":"docs/BehaviorBuilder.lua"}},{"name":"Physics","desc":"Opens the Physics configuration group.\\n\\nAvailable setters: `:MaxDistance()`, `:MinSpeed()`, `:Gravity()`,\\n`:Acceleration()`, `:RaycastParams()`. Call `:Done()` to return to the\\nroot builder.","params":[],"returns":[{"desc":"","lua_type":"PhysicsBuilder"}],"function_type":"method","source":{"line":68,"path":"docs/BehaviorBuilder.lua"}},{"name":"Pierce","desc":"Opens the Pierce configuration group.\\n\\nAvailable setters: `:Filter()`, `:Max()`, `:SpeedThreshold()`,\\n`:SpeedRetention()`, `:NormalBias()`. Call `:Done()` to return.","params":[],"returns":[{"desc":"","lua_type":"PierceBuilder"}],"function_type":"method","source":{"line":78,"path":"docs/BehaviorBuilder.lua"}},{"name":"Bounce","desc":"Opens the Bounce configuration group.\\n\\nAvailable setters: `:Filter()`, `:Max()`, `:SpeedThreshold()`,\\n`:Restitution()`, `:MaterialRestitution()`, `:NormalPerturbation()`.\\nCall `:Done()` to return.","params":[],"returns":[{"desc":"","lua_type":"BounceBuilder"}],"function_type":"method","source":{"line":89,"path":"docs/BehaviorBuilder.lua"}},{"name":"HighFidelity","desc":"Opens the HighFidelity configuration group.\\n\\nAvailable setters: `:SegmentSize()`, `:FrameBudget()`, `:AdaptiveScale()`,\\n`:MinSegmentSize()`, `:MaxBouncesPerFrame()`. Call `:Done()` to return.","params":[],"returns":[{"desc":"","lua_type":"HighFidelityBuilder"}],"function_type":"method","source":{"line":99,"path":"docs/BehaviorBuilder.lua"}},{"name":"CornerTrap","desc":"Opens the CornerTrap configuration group.\\n\\nAvailable setters: `:TimeThreshold()`, `:NormalDotThreshold()`,\\n`:DisplacementThreshold()`. Call `:Done()` to return.","params":[],"returns":[{"desc":"","lua_type":"CornerTrapBuilder"}],"function_type":"method","source":{"line":109,"path":"docs/BehaviorBuilder.lua"}},{"name":"Cosmetic","desc":"Opens the Cosmetic configuration group.\\n\\nAvailable setters: `:Template()`, `:Container()`, `:Provider()`.\\nCall `:Done()` to return.","params":[],"returns":[{"desc":"","lua_type":"CosmeticBuilder"}],"function_type":"method","source":{"line":119,"path":"docs/BehaviorBuilder.lua"}},{"name":"Debug","desc":"Opens the Debug configuration group.\\n\\nAvailable setters: `:Visualize()`. Call `:Done()` to return.","params":[],"returns":[{"desc":"","lua_type":"DebugBuilder"}],"function_type":"method","source":{"line":128,"path":"docs/BehaviorBuilder.lua"}},{"name":"Build","desc":"Validates the current configuration and returns a frozen `HybridBehavior`\\ntable ready to pass to [HybridSolver:Fire].\\n\\nAll validation errors are collected and logged together so every problem is\\nreported at once. Returns `nil` if any validation error is found.\\n\\nDoes **not** consume the builder \u2014 call `:Build()` multiple times to produce\\nindependent frozen tables from the same configuration.","params":[],"returns":[{"desc":"Frozen behavior table, or nil if validation failed.","lua_type":"HybridBehavior?"}],"function_type":"method","source":{"line":142,"path":"docs/BehaviorBuilder.lua"}},{"name":"Sniper","desc":"Returns a pre-configured builder for a high-velocity, long-range,\\npierce-capable projectile. No bouncing.\\n\\nSuitable for rifles and anti-materiel weapons. Further chain methods\\nbefore calling `:Build()` to customise.","params":[],"returns":[{"desc":"","lua_type":"BehaviorBuilder"}],"function_type":"static","source":{"line":155,"path":"docs/BehaviorBuilder.lua"}},{"name":"Grenade","desc":"Returns a pre-configured builder for a low-speed, gravity-affected,\\nbouncy projectile. No piercing.\\n\\nSuitable for thrown grenades or bouncing explosives.","params":[],"returns":[{"desc":"","lua_type":"BehaviorBuilder"}],"function_type":"static","source":{"line":165,"path":"docs/BehaviorBuilder.lua"}},{"name":"Pistol","desc":"Returns a pre-configured builder for a standard short-to-mid range\\nprojectile with single pierce and no bounce.\\n\\nSuitable for handguns and SMGs.","params":[],"returns":[{"desc":"","lua_type":"BehaviorBuilder"}],"function_type":"static","source":{"line":175,"path":"docs/BehaviorBuilder.lua"}}],"properties":[],"types":[],"name":"BehaviorBuilder","desc":"Fluent typed configuration builder for [HybridSolver].\\n\\nInstead of constructing raw behavior tables by hand, chain namespace methods\\nand call `:Build()` to produce a validated, frozen `HybridBehavior`.\\n\\n```lua\\nlocal Behavior = BehaviorBuilder.new()\\n    :Physics()\\n        :MaxDistance(500)\\n        :MinSpeed(5)\\n    :Done()\\n    :Bounce()\\n        :Max(3)\\n        :Restitution(0.7)\\n        :Filter(function(ctx, result, vel)\\n            return result.Instance:HasTag(\\"Bouncy\\")\\n        end)\\n    :Done()\\n    :Build()\\n```\\n\\n**Namespace overview:**\\n\\n| Method | Configures |\\n|--------|-----------|\\n| `:Physics()` | MaxDistance, MinSpeed, Gravity, Acceleration, RaycastParams |\\n| `:Pierce()` | Filter, Max, SpeedThreshold, SpeedRetention, NormalBias |\\n| `:Bounce()` | Filter, Max, SpeedThreshold, Restitution, MaterialRestitution, NormalPerturbation |\\n| `:HighFidelity()` | SegmentSize, FrameBudget, AdaptiveScale, MinSegmentSize, MaxBouncesPerFrame |\\n| `:CornerTrap()` | TimeThreshold, NormalDotThreshold, DisplacementThreshold |\\n| `:Cosmetic()` | Template, Container, Provider |\\n| `:Debug()` | Visualize |\\n\\nBuilders are **reusable** \u2014 call `:Build()` multiple times to produce independent\\nfrozen tables. This is useful for weapon archetypes where many bullets share\\nthe same base configuration.\\n\\n:::tip Presets\\nUse [BehaviorBuilder.Sniper], [BehaviorBuilder.Grenade], or [BehaviorBuilder.Pistol]\\nas a starting point, then chain additional overrides before calling `:Build()`.\\n:::","source":{"line":46,"path":"docs/BehaviorBuilder.lua"}}')}}]);